-- VERIFICAR
SELECT 'comprobante'         AS tabla, COUNT(*) AS registros FROM comprobante
UNION ALL SELECT 'comprobante_detalle', COUNT(*) FROM comprobante_detalle;

-- RESUMEN DE VENTAS REALES POR MES
SELECT YEAR(fecha_emision) anio, MONTH(fecha_emision) mes,
  COUNT(*) n_comp, ROUND(SUM(mto_total),2) ventas_total
FROM comprobante WHERE anulado=0
GROUP BY anio,mes ORDER BY anio,mes;